export default{
	data() {
		return {
			TabCur:0,
			Tab:['客户查询','房源查询'],
			requestData:{
				keyword: '', //搜索
				page: 1,
				limit:15
			},
			customerList:[],
			per_page:0,
			current_page:0,
			last_page:0,
			total:0
		}
	},
	onShow() {
		this.TabCur = 0;
	},
	methods:{
		cname(name){
			return this.$tools.cName(name)
		},
		search(){
			this.customerList = [];
			this.getCustomerList();
		},
		getCustomerList() {
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.mcSearchCustomapi(this.requestData, res => {
				res.data.data.forEach(resp => {
					this.customerList.push(resp);
				});
				this.per_page = res.data.per_page; //一页多少条数据；
				this.current_page = res.data.current_page; //当前页数；
				this.last_page = res.data.last_page; //一共多少页；
				this.total = res.data.total; //总条数
			});
		},
		tabSelect(e){
			this.TabCur = e.currentTarget.dataset.id;
			if(this.TabCur == 1){
				uni.navigateTo({
					url:'/pages/search/search'
				})
			}
		},
		InputFocus(e) {
			this.InputBottom = e.detail.height;
		},
		InputBlur(e) {
			this.InputBottom = 0;
		},
	}
}
